CREATE TABLE IF NOT EXISTS `profesores` (`id` int(11) NOT NULL AUTO_INCREMENT, `password` varchar(255) NOT NULL, `correo` varchar(100) NOT NULL, `nombre` varchar(100) DEFAULT NULL, PRIMARY KEY (`id`), UNIQUE KEY `correo` (`correo`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `alumnos` (`id` int(11) NOT NULL AUTO_INCREMENT, `nombre` varchar(100) NOT NULL, `correo` varchar(100) NOT NULL, `password` varchar(255) NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `correo` (`correo`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `materias` (`id` int(11) NOT NULL AUTO_INCREMENT, `nombre` varchar(100) NOT NULL, `carrera` varchar(100) NOT NULL, `hora` varchar(50) NOT NULL, `codigo` varchar(10) NOT NULL DEFAULT '', `profesor_id` int(11) NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `codigo` (`codigo`), FOREIGN KEY (`profesor_id`) REFERENCES `profesores` (`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `alumno_materias` (`id` int(11) NOT NULL AUTO_INCREMENT, `alumno_id` int(11) NOT NULL, `materia_id` int(11) NOT NULL, `fecha_union` datetime DEFAULT current_timestamp(), PRIMARY KEY (`id`), FOREIGN KEY (`alumno_id`) REFERENCES `alumnos` (`id`) ON DELETE CASCADE, FOREIGN KEY (`materia_id`) REFERENCES `materias` (`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `asignaciones` (`id` int(11) NOT NULL AUTO_INCREMENT, `titulo` varchar(150) NOT NULL, `descripcion` text DEFAULT NULL, `fecha_limite` date DEFAULT NULL, `archivo_apoyo` varchar(255) DEFAULT NULL, `materia_id` int(11) NOT NULL, PRIMARY KEY (`id`), FOREIGN KEY (`materia_id`) REFERENCES `materias` (`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `asignacion_archivos` (`id` int(11) NOT NULL AUTO_INCREMENT, `asignacion_id` int(11) NOT NULL, `nombre_original` varchar(255) NOT NULL, `nombre_guardado` varchar(255) NOT NULL, PRIMARY KEY (`id`), FOREIGN KEY (`asignacion_id`) REFERENCES `asignaciones` (`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `entregas` (`id` int(11) NOT NULL AUTO_INCREMENT, `alumno_nombre` varchar(100) NOT NULL, `alumno_id` int(11) DEFAULT NULL, `archivo` varchar(255) NOT NULL, `estado` enum('pendiente','entregada') DEFAULT 'pendiente', `asignacion_id` int(11) NOT NULL, `fecha_entrega` datetime DEFAULT current_timestamp(), `calificacion` int(11) DEFAULT NULL, PRIMARY KEY (`id`), FOREIGN KEY (`asignacion_id`) REFERENCES `asignaciones` (`id`) ON DELETE CASCADE, FOREIGN KEY (`alumno_id`) REFERENCES `alumnos` (`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;